def assemble_prompt(user_query: str, retrieved_chunks: list[str]) -> list[dict]:
    # 1. Format the chunks with clear delimiters and source IDs
    context_str = ""
    for i, chunk in enumerate(retrieved_chunks, 1):
        context_str += f"<source_{i}>\n{chunk}\n</source_{i}>\n\n"

    # 2. Build the System prompt with strict grounding rules
    system_msg = {
        "role": "system",
        "content": (
            "You are an expert assistant. Answer the user's question USING ONLY "
            "the provided context. If the answer is not in the context, say 'I don't know'. "
            "Cite your sources using [Source X].\n\n"
            f"<context>\n{context_str}</context>"
        )
    }

    # 3. Place the user query last
    user_msg = {
        "role": "user",
        "content": user_query
    }

    return [system_msg, user_msg]
